1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1,  0],          [1,  0],
6	  [-1,  1], [0,  1], [1,  1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const isAliveNextGeneration = (wasAlive: boolean, liveNeighborCount: number): boolean =>
15	  liveNeighborCount === 3 || (wasAlive && liveNeighborCount === 2);
16	
17	type CandidateTally = { cell: Cell; liveNeighborCount: number };
18	
19	const tallyCandidatesFromLiveCells = (liveCells: Cell[]): Map<string, CandidateTally> => {
20	  const tallies = new Map<string, CandidateTally>();
21	  for (const liveCell of liveCells) {
22	    for (const neighbor of neighborsOf(liveCell)) {
23	      const key = cellKey(neighbor);
24	      const existing = tallies.get(key);
25	      if (existing) existing.liveNeighborCount++;
26	      else tallies.set(key, { cell: neighbor, liveNeighborCount: 1 });
27	    }
28	  }
29	  return tallies;
30	};
31	
32	export function nextGeneration(liveCells: Cell[]): Cell[] {
33	  const liveKeys = new Set(liveCells.map(cellKey));
34	  const survivors: Cell[] = [];
35	  for (const [key, { cell, liveNeighborCount }] of tallyCandidatesFromLiveCells(liveCells)) {
36	    if (isAliveNextGeneration(liveKeys.has(key), liveNeighborCount)) {
37	      survivors.push(cell);
38	    }
39	  }
40	  return survivors;
41	}
